describe('Running Dashboard Extended — YtdStats card', () => {
  before(() => {
    cy.setupApiAuthCookies()
  })

  it('renders #ytdStatsCard when ytd_stats.distance_m > 0', () => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubSupportingApis()

    cy.intercept('GET', '/api/running/v1/dashboard*', {
      statusCode: 200,
      body: buildDashboardBody({
        ytd_stats: {
          count: 42,
          distance_m: 150000,
          moving_time_sec: 54000,
          elevation_gain_m: 800,
          achievement_count: 3,
        },
      }),
    }).as('getDashboard')

    cy.viewport(1280, 720)
    cy.visit('/main/running/dashboard')
    cy.wait('@getDashboard')

    cy.get(`#${IDS.ytd_stats_card}`).should('exist')
  })

  it('YtdStats shows total distance with 2 decimal places (150000m → 150.00 km)', () => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubSupportingApis()

    cy.intercept('GET', '/api/running/v1/dashboard*', {
      statusCode: 200,
      body: buildDashboardBody({
        ytd_stats: {
          count: 42,
          distance_m: 150000,
          moving_time_sec: 54000,
          elevation_gain_m: 800,
          achievement_count: 3,
        },
      }),
    }).as('getDashboard')

    cy.viewport(1280, 720)
    cy.visit('/main/running/dashboard')
    cy.wait('@getDashboard')

    cy.get(`#${IDS.ytd_stats_card}`).scrollIntoView().contains('150.00 km').should('be.visible')
  })

  it('does NOT render #ytdStatsCard when ytd_stats.distance_m === 0', () => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubSupportingApis()

    cy.intercept('GET', '/api/running/v1/dashboard*', {
      statusCode: 200,
      body: buildDashboardBody({
        ytd_stats: {
          count: 0,
          distance_m: 0,
          moving_time_sec: 0,
          elevation_gain_m: 0,
          achievement_count: 0,
        },
      }),
    }).as('getDashboard')

    cy.viewport(1280, 720)
    cy.visit('/main/running/dashboard')
    cy.wait('@getDashboard')

    cy.get(`#${IDS.ytd_stats_card}`).should('not.exist')
  })

  it('does NOT render #ytdStatsCard when ytd_stats is null', () => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubSupportingApis()

    cy.intercept('GET', '/api/running/v1/dashboard*', {
      statusCode: 200,
      body: buildDashboardBody({ ytd_stats: null }),
    }).as('getDashboard')

    cy.viewport(1280, 720)
    cy.visit('/main/running/dashboard')
    cy.wait('@getDashboard')

    cy.get(`#${IDS.ytd_stats_card}`).should('not.exist')
  })
})

