describe('Running Dashboard Extended — Sync status bar', () => {
  before(() => {
    cy.setupApiAuthCookies()
  })

  it('#syncStatusBar shows "Never" when last_sync_at is null', () => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubSupportingApis()

    // Stub the auto-sync that fires when last_sync_at is null
    cy.intercept('POST', '/api/running/v1/auth/strava/sync', {
      statusCode: 200,
      body: { synced: 0 },
    }).as('syncStrava')

    cy.intercept('GET', '/api/running/v1/dashboard*', {
      statusCode: 200,
      body: buildDashboardBody({ last_sync_at: null }),
    }).as('getDashboard')

    cy.viewport(1280, 720)
    cy.visit('/main/running/dashboard')
    cy.wait('@getDashboard')

    // Wait for auto-sync to complete before asserting
    cy.wait('@syncStrava')

    cy.get(`#${IDS.sync_status_bar}`).should('be.visible')
    cy.get(`#${IDS.sync_status_bar}`).contains('Never').should('be.visible')
  })

  it('#syncBtn_dashboard is visible and clickable', () => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubSupportingApis()

    cy.intercept('POST', '/api/running/v1/auth/strava/sync', {
      statusCode: 200,
      body: { synced: 0 },
    }).as('syncStrava')

    cy.intercept('GET', '/api/running/v1/dashboard*', {
      statusCode: 200,
      body: buildDashboardBody({ last_sync_at: new Date().toISOString() }),
    }).as('getDashboard')

    cy.viewport(1280, 720)
    cy.visit('/main/running/dashboard')
    cy.wait('@getDashboard')

    cy.get(`#${IDS.sync_btn}`).should('be.visible').and('not.be.disabled')
  })

  it('clicking #syncBtn_dashboard triggers POST to /api/running/v1/auth/strava/sync', () => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubSupportingApis()

    // First stub is for the auto-sync on mount (last_sync_at recent — should not auto-sync)
    cy.intercept('POST', '/api/running/v1/auth/strava/sync', {
      statusCode: 200,
      body: { synced: 3 },
    }).as('syncStrava')

    cy.intercept('GET', '/api/running/v1/dashboard*', {
      statusCode: 200,
      body: buildDashboardBody({ last_sync_at: new Date().toISOString() }),
    }).as('getDashboard')

    cy.viewport(1280, 720)
    cy.visit('/main/running/dashboard')
    cy.wait('@getDashboard')

    cy.get(`#${IDS.sync_btn}`).click()
    cy.wait('@syncStrava')
  })

  it('#syncResultMsg shows "X new activities" when synced count > 0', () => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubSupportingApis()

    cy.intercept('POST', '/api/running/v1/auth/strava/sync', {
      statusCode: 200,
      body: { synced: 5 },
    }).as('syncStrava')

    cy.intercept('GET', '/api/running/v1/dashboard*', {
      statusCode: 200,
      body: buildDashboardBody({ last_sync_at: new Date().toISOString() }),
    }).as('getDashboard')

    cy.viewport(1280, 720)
    cy.visit('/main/running/dashboard')
    cy.wait('@getDashboard')

    cy.get(`#${IDS.sync_btn}`).click()
    cy.wait('@syncStrava')

    cy.get(`#${IDS.sync_result_msg}`, { timeout: 8000 }).should('be.visible')
    cy.get(`#${IDS.sync_result_msg}`).contains('new activit').should('be.visible')
  })

  it('#syncResultMsg shows "Already up to date" when synced count = 0', () => {
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubSupportingApis()

    cy.intercept('POST', '/api/running/v1/auth/strava/sync', {
      statusCode: 200,
      body: { synced: 0 },
    }).as('syncStrava')

    cy.intercept('GET', '/api/running/v1/dashboard*', {
      statusCode: 200,
      body: buildDashboardBody({ last_sync_at: new Date().toISOString() }),
    }).as('getDashboard')

    cy.viewport(1280, 720)
    cy.visit('/main/running/dashboard')
    cy.wait('@getDashboard')

    cy.get(`#${IDS.sync_btn}`).click()
    cy.wait('@syncStrava')

    cy.get(`#${IDS.sync_result_msg}`, { timeout: 8000 }).should('be.visible')
    cy.get(`#${IDS.sync_result_msg}`).contains('Already up to date').should('be.visible')
  })
})

