describe('Running Dashboard Extended — Activity type filter', () => {
  before(() => {
    cy.setupApiAuthCookies()
  })

  beforeEach(() => {
    cy.viewport(1280, 720)
    cy.setupApiAuthCookies()
    stubRtUsers()
    stubSupportingApis()

    cy.intercept('POST', '/api/running/v1/auth/strava/sync', {
      statusCode: 200,
      body: { synced: 0 },
    }).as('syncStrava')

    cy.intercept('GET', '/api/running/v1/dashboard*', {
      statusCode: 200,
      body: buildDashboardBody({
        last_sync_at: new Date().toISOString(),
        recent_activities: [
          {
            id: 'act-1',
            started_at: '2026-05-20T07:00:00Z',
            distance_m: 10000,
            duration_sec: 3600,
            avg_pace_sec_per_km: 360,
            avg_hr: 148,
            activity_type: 'easy',
            source: 'strava',
          },
          {
            id: 'act-2',
            started_at: '2026-05-19T07:00:00Z',
            distance_m: 8000,
            duration_sec: 2400,
            avg_pace_sec_per_km: 300,
            avg_hr: 165,
            activity_type: 'tempo',
            source: 'strava',
          },
        ],
      }),
    }).as('getDashboard')

    cy.visit('/main/running/dashboard')
    cy.wait('@getDashboard')
  })

  it('activity type filter renders when recent_activities has multiple types', () => {
    cy.contains('Filter:').should('be.visible')
    cy.contains('button', 'All').should('be.visible')
  })

  it('clicking a filter button adds ring styling (active state)', () => {
    // Click 'Easy' filter button (activity_type: easy maps to label 'Easy')
    cy.contains('button', 'Easy').click()

    cy.contains('button', 'Easy').should('have.class', 'ring-1')
  })
})
